#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    if (x[0] == y[0]) return x[1] - y[1];
    return x[0] - y[0];
}
int main() {
    int n;
    scanf("%d", &n);
    int people[n][2];
    for (int i = 0; i < n; i++) {
        scanf("%d %d", &people[i][0], &people[i][1]);
    }
    qsort(people, n, sizeof(people[0]), compare);
    int stops = 0;
    int i = 0, j = n - 1;
    while (i <= j) {
        if (people[i][0] < people[j][0]) {
            stops++;
            i++;
        } else if (people[i][0] > people[j][0]) {
            stops++;
            j--;
        } else {
            stops++;
            i++;
            j--;
        }
    }
    printf("%d\n", stops);
    return 0;
}

